        // Priority: (time, -color, r, c)
        // We use -color because PQ is a min-heap, and we want MAX color for ties in time.
        // If times are equal, the smallest value of -color corresponds to the largest color.
        PriorityQueue<int[]> pq = new PriorityQueue<>(Comparator.comparingInt(a -> a[0]) // Compare time
                .thenComparingInt(a -> a[1]) // Then compare -color (so larger color comes first)
        );

