            int r = (int) source[0];
            int c = (int) source[1];
            int color = (int) source[2];

            // If multiple sources are at the same location (problem guarantees they are not, but safety check)
            if (state[r][c][0] == -1 || 0 < state[r][c][0]) {
                state[r][c][0] = 0; // Time 0
                state[r][c][1] = color;
                pq.offer(new int[]{0, -color, r, c});
            } else if (0 == state[r][c][0] && color > state[r][c][1]) {
                // Update color if initial color is higher at time 0
                state[r][c][1] = color;
                // Re-add to PQ might be necessary depending on PQ implementation, but for source initialization, this is fine.
                pq.offer(new int[]{0, -color, r, c});
            }
        }

        int[] dr = {0, 0, 1, -1};
        int[] dc = {1, -1, 0, 0};

        while (!pq.isEmpty()) {
            int[] current = pq.poll();
            int time = current[0];
            int negColor = current[1];
            int r = current[2];
            int c = current[3];
            int color = -negColor;

            // Check for stale entries (we found a better path/color already)
            if (time > state[r][c][0] || (time == state[r][c][0] && color < state[r][c][1])) {
                continue;
            }

            // Diffuse to neighbors
            for (int i = 0; i < 4; i++) {
                int nr = r + dr[i];
                int nc = c + dc[i];

                if (nr >= 0 && nr < N && nc >= 0 && nc < M) {
                    int nextTime = time + 1;
                    int nextColor = color;

                    // Check if we found a strictly better way to reach (nr, nc)
                    // 1. Shorter time always wins.
                    if (state[nr][nc][0] == -1 || nextTime < state[nr][nc][0]) {
                        state[nr][nc][0] = nextTime;
                        state[nr][nc][1] = nextColor;
                        pq.offer(new int[]{nextTime, -nextColor, nr, nc});
                    }
                    // 2. Same time, but higher color wins.
                    else if (nextTime == state[nr][nc][0]) {
                        if (nextColor > state[nr][nc][1]) {
                            state[nr][nc][1] = nextColor;
                            // Update PQ entry for (nr, nc) with the higher color at the same time
                            pq.offer(new int[]{nextTime, -nextColor, nr, nc});
                        }
                    }
                    // 3. Same time, same color: do nothing.
                }
            }
        }

        // Construct the final result array
        long[][] result = new long[N][M];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                // If state[i][j][0] is still -1, it means it was never reached (which shouldn't happen if N*M >= 1 and sources exist)
                // Based on the problem, all cells will eventually be colored unless N*M=0, but constraints say N, M >= 1.
                // If it somehow remained uncolored, its color should default to 0 as per initial description,
                // but the BFS structure ensures it gets the max color if reachable.
                result[i][j] = state[i][j][1];
            }
        }

        return result;
    }
