     * The "cost" is the time taken to reach a cell.
     * We prioritize cells by time, and for the same time, by the maximum color encountered.
     *
     * @param n The number of rows.
     * @param m The number of columns.
     * @param sources An array where sources[i] = [r_i, c_i, color_i].
     * @return A 2D array representing the final color of each cell.
     */
    public static long[][] solve(long n, long m, long[][] sources) {
        int N = (int) n;
        int M = (int) m;

        // Initialize the grid to 0 (uncolored)
        // We use long[][] for the output as per the signature, though colors are int range,
        // the return type dictates it.
        long[][] finalColors = new long[N][M];

        // dist[r][c] stores the minimum time required to color cell (r, c)
        // Initialize to infinity (a large value)
        long INF = Long.MAX_VALUE / 2; // Use half max to avoid overflow during addition
        long[][] dist = new long[N][M];
        for (int i = 0; i < N; i++) {
            Arrays.fill(dist[i], INF);
        }

        // State for the priority queue: [time, negative_color, r, c]
        // We use negative color because PriorityQueue is a min-heap, and we want max color first 
        // for tie-breaking at the same time.
        // The actual color is positive, so -color achieves max-heap behavior on color when time is equal.
        // Priority: 1. Minimum Time (d), 2. Maximum Color (-c)
        PriorityQueue<long[]> pq = new PriorityQueue<>(
            Comparator.comparingLong((long[] a) -> a[0]) // Compare by time (a[0]) ascending
                      .thenComparingLong(a -> a[1])      // Compare by -color (a[1]) ascending, meaning color descending
        );

        // Process initial sources
        for (long[] source : sources) {
            int r = (int) source[0];
            int c = (int) source[1];
            int color = (int) source[2];

            dist[r][c] = 0;
            finalColors[r][c] = color;
            // Time = 0, Negative Color = -color, R, C
            pq.offer(new long[]{0, -color, r, c});
        }

        int[] dr = {-1, 1, 0, 0};
        int[] dc = {0, 0, -1, 1};

        while (!pq.isEmpty()) {
            long[] current = pq.poll();
            long time = current[0];
            long negColor = current[1];
            int r = (int) current[2];
            int c = (int) current[3];
            int currentColor = (int) -negColor;

            // If we found a better path to (r, c) already, skip.
            // Since we prioritize by time, if the current time is greater than known shortest time, skip.
            if (time > dist[r][c]) {
                continue;
            }

            for (int i = 0; i < 4; i++) {
                int nr = r + dr[i];
                int nc = c + dc[i];

                if (nr >= 0 && nr < N && nc >= 0 && nc < M) {
                    // Check if the neighbor is uncolored OR if the new path offers an improvement

                    // The problem states: "If multiple colors arrive at the same time step, 
                    // the cell adopts the maximum color."
                    // This means we are looking for the earliest time T, and among all paths 
                    // arriving at T, we choose the one with max color.

                    // 1. New arrival time: time + 1
                    long newTime = time + 1;

                    // 2. Current best arrival state for (nr, nc)
                    long currentBestTime = dist[nr][nc];
                    long currentBestColor = finalColors[nr][nc];

                    // Case 1: New path reaches (nr, nc) strictly earlier
                    if (newTime < currentBestTime) {
                        dist[nr][nc] = newTime;
                        finalColors[nr][nc] = currentColor;
                        pq.offer(new long[]{newTime, -currentColor, nr, nc});
                    } 
                    // Case 2: New path arrives at the same time as the current best path
                    else if (newTime == currentBestTime) {
                        // If the new color is greater than the currently recorded color, update
                        if (currentColor > currentBestColor) {
                            finalColors[nr][nc] = currentColor;
                            // Re-add to PQ to propagate this potentially higher color forward,
                            // although technically the distance hasn't changed, the associated 'color' 
                            // that defines the state might need updating.
                            // Since the PQ prioritizes (Time, -Color), pushing it again with the 
                            // better color at the same time will ensure it's processed correctly.
                            pq.offer(new long[]{newTime, -currentColor, nr, nc});
                        }
                    }
                    // Case 3: New path is later (newTime > currentBestTime), ignore.
                }
            }
        }

        return finalColors;
    }
